 19→#[derive(Subcommand, Debug)]
 20→enum Commands {
 21→    /// Print the changeID for a revision
 22→    Chid(chid::ChidArgs),
 23→
 24→    /// Show full description of a commit
 25→    Desc(desc::DescArgs),
 26→
 27→    /// List commits in a jj repo
 28→    List(list::ListArgs),
 29→
