 37→fn main() -> ExitCode {
 38→    let cli = Cli::parse();
 39→
 40→    match cli.command {
 41→        Commands::Chid(args) => {
 42→            if let Err(e) = chid::chid(&args) {
 43→                eprintln!("error: {e}");
 44→                return ExitCode::FAILURE;
 45→            }
 46→            ExitCode::SUCCESS
 47→        }
 48→        Commands::Desc(args) => {
 49→            if let Err(e) = desc::desc(&args) {
 50→                eprintln!("error: {e}");
 51→                return ExitCode::FAILURE;
 52→            }
 53→            ExitCode::SUCCESS
 54→        }
 55→        Commands::List(args) => {
 56→            if let Err(e) = list::list(&args) {
 57→                eprintln!("error: {e}");
 58→                return ExitCode::FAILURE;
 59→            }
 60→            ExitCode::SUCCESS
 61→        }
 62→        Commands::Show(args) => {
 63→            if let Err(e) = show::show(&args) {
 64→                eprintln!("error: {e}");
 65→                return ExitCode::FAILURE;
 66→            }
 67→            ExitCode::SUCCESS
 68→        }
 69→        Commands::Finalize(args) => {
 70→            let opts = args.into_opts();
 71→            finalize::log_msg(&opts.log, "main: finalize entry");
 72→            match finalize::finalize(&opts) {
 73→                Ok(()) => {
 74→                    finalize::log_msg(&opts.log, "main: finalize exit ok");
 75→                    ExitCode::SUCCESS
 76→                }
 77→                Err(e) => {
 78→                    finalize::log_msg(&opts.log, &format!("main: finalize exit err={e}"));
 79→                    eprintln!("error: {e}");
 80→                    ExitCode::FAILURE
 81→                }
 82→            }
 83→        }
 84→    }
 85→}
