/// Separator style between repos in multi-repo output.
#[derive(Debug, Clone)]
pub enum Separator {
    /// Bold `==> path <==` header per repo (default).
    Default,
    /// Custom string between repos.
    Custom(String),
    /// No separator at all.
    None,
}

/// Resolve `-s` / `-S` flags into a `Separator`.
///
/// `-S` (no separator) takes precedence over `-s` (custom separator).
pub fn resolve_separator(custom: &Option<String>, suppress: bool) -> Separator {
    if suppress {
        Separator::None
    } else if let Some(s) = custom {
        Separator::Custom(s.clone())
    } else {
        Separator::Default
    }
}

/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
///
/// Separator style controls output between repos.
/// Continues past errors, printing them to stderr, and returns an error if any failed.
pub fn for_each_repo<F>(
    raw_repos: &[PathBuf],
    separator: &Separator,
    mut body: F,
) -> Result<(), Box<dyn std::error::Error>>
where
    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
{
    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
