    } else {
        raw_repos
            .iter()
            .flat_map(|p| {
                p.to_string_lossy()
                    .split(',')
                    .map(|s| PathBuf::from(s.trim()))
                    .collect::<Vec<_>>()
            })
            .collect()
    };
    let multi = repos.len() > 1;
    let mut first = true;
    let mut errors: Vec<String> = Vec::new();

    for repo_path in &repos {
