/// Separator style between repos in multi-repo output.
#[derive(Debug, Clone)]
pub enum Separator {
    /// Bold `==> path <==` header per repo (default).
    Default,
    /// Custom string between repos.
    Custom(String),
    /// No separator at all.
    None,
}

/// Resolve `-s` / `-S` flags into a `Separator`.
///
/// `-S` (no separator) takes precedence over `-s` (custom separator).
pub fn resolve_separator(custom: &Option<String>, suppress: bool) -> Separator {
    if suppress {
        Separator::None
    } else if let Some(s) = custom {
        Separator::Custom(s.clone())
    } else {
        Separator::Default
    }
}

