/// Header style between repos in multi-repo output.
#[derive(Debug, Clone)]
pub enum Header {
    /// Bold `==> path <==` header per repo (default).
    Default,
    /// Custom decoration: `deco path deco`.
    Custom(String),
    /// No header at all.
    None,
}

/// Resolve `-s` / `-S` flags into a `Header`.
///
/// `-S` (no header) takes precedence over `-s` (custom decoration).
