        let (ids, anchor_index) =
            common::collect_ids(workspace, repo, &spec.rev, spec.desc_count, spec.anc_count)?;

        let mut first = true;
        for (i, commit_id) in ids.iter().enumerate() {
            if !first {
                println!("────────────────────────────────────────");
            }
            first = false;

