        assert_eq!(s.anc_count, Some(0));
    }

    #[test]
    fn resolve_spec_both() {
        let s = resolve_spec(Some("..@.."), Some(5), "@", None, "@");
        assert_eq!(s.rev, "@");
        assert_eq!(s.desc_count, Some(2)); // 4/2 = 2 descendants
        assert_eq!(s.anc_count, Some(2)); // 4-2 = 2 ancestors
    }

    #[test]
